query:
cat {{{lookup}}}
| where createdtime > (now () - (1000 * 60 * 60 * 24 * 30))
//| formatdate(tolong(createdtime),"yyyy-MM") as month
| concat(severity,":",severityname," - ",resolution) as state 
| if(isnull(confidence),0,confidence) as confidence
| count as insights,count_distinct(entityvalue) as entities,pct(timetoresponse,50) as MTTResponse,pct(timetoremediation,50) as MTTResolution,pct(timetodetection,50) as MTTDetection by state | sort state asc
//| round(avg_riskscore,1) as avg_riskscore | round(avg_confidence,2) as avg_confidence
|round(MTTResponse/60) as MTTResponse | round(MTTResolution/60) as  MTTResolution | round(MTTDetection/60) as MTTDetection
